def calculate_relevance_score(query, document):
    # Example: BM25 + Embedding similarity
    bm25_score = calculate_bm25_similarity(query, document)
    embedding_sim = calculate_embedding_similarity(query, document)

    combined_score = (bm25_score * 0.7) + (embedding_sim * 0.3)
    return combined_score

def rank_documents_by_relevance(query, documents):
    ranked_docs = sorted(documents, key=lambda doc: calculate_relevance_score(query, doc), reverse=True)
    return ranked_docs
